258	func (h *HugoSites) resolveFirstSite(matrix sitesmatrix.VectorStore) *Site {
259		var s *Site
260		var ok bool
261		matrix.ForEachVector(func(v sitesmatrix.Vector) bool {
262			if s, ok = h.sitesVersionsRolesMap[v]; ok {
263				return false
264			}
265			return true
266		})
267		if s == nil {
268			panic(fmt.Sprintf("no site found for matrix %s", matrix))
269		}
270	
271		return s
272	}
