286	type fatalErrorHandler struct {
287		mu sync.Mutex
288	
289		h *HugoSites
290	
291		err error
292	
293		done  bool
294		donec chan bool // will be closed when done
295	}
296	
297	// FatalError error is used in some rare situations where it does not make sense to
298	// continue processing, to abort as soon as possible and log the error.
299	func (f *fatalErrorHandler) FatalError(err error) {
300		f.mu.Lock()
301		defer f.mu.Unlock()
302		if !f.done {
303			f.done = true
304			close(f.donec)
305		}
306		f.err = err
307	}
308	
309	// Stop stops the fatal error handler without setting an error.
310	func (f *fatalErrorHandler) Stop() {
311		f.mu.Lock()
312		defer f.mu.Unlock()
313		if !f.done {
314			f.done = true
315			close(f.donec)
316		}
317	}
318	
319	func (f *fatalErrorHandler) getErr() error {
320		f.mu.Lock()
321		defer f.mu.Unlock()
322		return f.err
323	}
324	
325	func (f *fatalErrorHandler) Done() <-chan bool {
326		return f.donec
327	}
