443	func (h *HugoSites) onPageRender() {
444		pagesRendered := h.buildCounters.pageRenderCounter.Add(1)
445		numPagesToRender := h.progressReporter.numPagesToRender.Load()
446		n := numPagesToRender / 30
447		if n == 0 {
448			n = 1
449		}
450		if pagesRendered%n == 0 {
451			h.reportProgress(func() (terminal.ProgressState, float64) {
452				pr := h.progressReporter
453				if pr.renderProgressStart == 0.0 && pr.state == terminal.ProgressNormal {
454					pr.renderProgressStart = pr.progress
455				}
456				pagesProgress := pr.renderProgressStart + float64(pagesRendered)/float64(numPagesToRender)*(1.0-pr.renderProgressStart)
457				return terminal.ProgressNormal, pagesProgress
458			})
459		}
460	}
