517	// GetContentPage finds a Page with content given the absolute filename.
518	// Returns nil if none found.
519	func (h *HugoSites) GetContentPage(filename string) page.Page {
520		var p page.Page
521	
522		h.withPage(func(s string, p2 *pageState) bool {
523			if p2.File() == nil {
524				return false
525			}
526	
527			if p2.File().FileInfo().Meta().Filename == filename {
528				p = p2
529				return true
530			}
531	
532			for _, r := range p2.Resources().ByType(pageResourceType) {
533				p3 := r.(page.Page)
534				if p3.File() != nil && p3.File().FileInfo().Meta().Filename == filename {
535					p = p3
536					return true
537				}
538			}
539	
540			return false
541		})
542	
543		return p
544	}
