590	func (h *HugoSites) withPage(fn func(s string, p *pageState) bool) {
591		for s := range h.allSites(nil) {
592			w := &doctree.NodeShiftTreeWalker[contentNode]{
593				Tree:     s.pageMap.treePages,
594				LockType: doctree.LockTypeRead,
595				Handle: func(s string, n contentNode) (radix.WalkFlag, error) {
596					if fn(s, n.(*pageState)) {
597						return radix.WalkStop, nil
598					}
599					return radix.WalkContinue, nil
600				},
601			}
602			_ = w.Walk(context.Background())
603		}
604	}
