110	func (fd *ResourceSourceDescriptor) init(r *Spec) error {
111		if len(fd.TargetBasePaths) == 0 {
112			// If not set, we publish the same resource to all hosts.
113			fd.TargetBasePaths = r.MultihostTargetBasePaths
114		}
115	
116		if fd.OpenReadSeekCloser == nil {
117			panic(errors.New("OpenReadSeekCloser is nil"))
118		}
119	
120		if fd.TargetPath == "" {
121			panic(errors.New("RelPath is empty"))
122		}
123	
124		if fd.Params == nil {
125			fd.Params = make(hmaps.Params)
126		}
127	
128		if fd.Path == nil {
129			fd.Path = r.Cfg.PathParser().Parse("", fd.TargetPath)
130		}
131	
132		if fd.TargetPath == "" {
133			fd.TargetPath = fd.Path.Path()
134		} else {
135			fd.TargetPath = paths.ToSlashPreserveLeading(fd.TargetPath)
136		}
137	
138		fd.BasePathRelPermalink = paths.ToSlashPreserveLeading(fd.BasePathRelPermalink)
139		if fd.BasePathRelPermalink == "/" {
140			fd.BasePathRelPermalink = ""
141		}
142		fd.BasePathTargetPath = paths.ToSlashPreserveLeading(fd.BasePathTargetPath)
143		if fd.BasePathTargetPath == "/" {
144			fd.BasePathTargetPath = ""
145		}
146	
147		fd.TargetPath = paths.ToSlashPreserveLeading(fd.TargetPath)
148	
149		if fd.NameNormalized == "" {
150			fd.NameNormalized = fd.TargetPath
151		}
152	
153		if fd.NameOriginal == "" {
154			fd.NameOriginal = fd.NameNormalized
155		}
156	
157		if fd.Title == "" {
158			fd.Title = fd.NameOriginal
159		}
160	
161		mediaType := fd.MediaType
162		if mediaType.IsZero() {
163			ext := fd.Path.Ext()
164			var (
165				found      bool
166				suffixInfo media.SuffixInfo
167			)
168			mediaType, suffixInfo, found = r.MediaTypes().GetFirstBySuffix(ext)
169			// TODO(bep) we need to handle these ambiguous types better, but in this context
170			// we most likely want the application/xml type.
171			if suffixInfo.Suffix == "xml" && mediaType.SubType == "rss" {
172				mediaType, found = r.MediaTypes().GetByType("application/xml")
173			}
174	
175			if !found {
176				// A fallback. Note that mime.TypeByExtension is slow by Hugo standards,
177				// so we should configure media types to avoid this lookup for most
178				// situations.
179				mimeStr := mime.TypeByExtension("." + ext)
180				if mimeStr != "" {
181					mediaType, _ = media.FromStringAndExt(mimeStr, ext)
182				}
183			}
184		}
185	
186		fd.MediaType = mediaType
187	
188		if fd.DependencyManager == nil {
189			fd.DependencyManager = r.Cfg.NewIdentityManager()
190		}
191	
192		return nil
193	}
