505	func (l *genericResource) Publish() error {
506		var err error
507		l.publishInit.Do(func() {
508			targetFilenames := l.getResourcePaths().TargetFilenames()
509	
510			if l.sourceFilenameIsHash {
511				// This is a processed image. We want to avoid copying it if it hasn't changed.
512				var changedFilenames []string
513				for _, targetFilename := range targetFilenames {
514					if _, err := l.getSpec().BaseFs.PublishFs.Stat(targetFilename); err == nil {
515						continue
516					}
517					changedFilenames = append(changedFilenames, targetFilename)
518				}
519				if len(changedFilenames) == 0 {
520					return
521				}
522				targetFilenames = changedFilenames
523			}
524			var fr hugio.ReadSeekCloser
525			fr, err = l.ReadSeekCloser()
526			if err != nil {
527				return
528			}
529			defer fr.Close()
530	
531			var fw io.WriteCloser
532			fw, err = helpers.OpenFilesForWriting(l.spec.BaseFs.PublishFs, targetFilenames...)
533			if err != nil {
534				return
535			}
536			defer fw.Close()
537	
538			_, err = io.Copy(fw, fr)
539		})
540	
541		return err
542	}
