581	func (r *genericResource) tryTransformedFileCache(key string, u *transformationUpdate) io.ReadCloser {
582		fi, f, meta, found := r.spec.ResourceCache.getFromFile(key)
583		if !found {
584			return nil
585		}
586		u.sourceFilename = &fi.Name
587		mt, _ := r.spec.MediaTypes().GetByType(meta.MediaTypeV)
588		u.mediaType = mt
589		u.data = meta.MetaData
590		u.targetPath = meta.Target
591		return f
592	}
