594	func (r *genericResource) mergeData(in map[string]any) {
595		if len(in) == 0 {
596			return
597		}
598		if r.sd.Data == nil {
599			r.sd.Data = make(map[string]any)
600		}
601		for k, v := range in {
602			if _, found := r.sd.Data[k]; !found {
603				r.sd.Data[k] = v
604			}
605		}
606	}
