665	func (r *resourceHash) init(l hugio.ReadSeekCloserProvider) error {
666		var initErr error
667		r.initOnce.Do(func() {
668			var hash uint64
669			var size int64
670			f, err := l.ReadSeekCloser()
671			if err != nil {
672				initErr = fmt.Errorf("failed to open source: %w", err)
673				return
674			}
675			defer f.Close()
676			hash, size, err = hashImage(f)
677			if err != nil {
678				initErr = fmt.Errorf("failed to calculate hash: %w", err)
679				return
680			}
681			r.value = hash
682			r.size = size
683		})
684	
685		return initErr
686	}
