620		base := p.PathInfo().BaseReTyped(p.m.pageConfig.Type)
621		return base, tplimpl.TemplateDescriptor{
622			Kind:           p.Kind(),
623			LayoutFromUser: p.Layout(),
624			OutputFormat:   f.Name,
625			MediaType:      f.MediaType.Type,
626			IsPlainText:    f.IsPlainText,
627		}
628	}
