630	func (ps *pageState) resolveTemplate(layouts ...string) (*tplimpl.TemplInfo, bool, error) {
631		dir, d := ps.GetInternalTemplateBasePathAndDescriptor()
632	
633		if len(layouts) > 0 {
634			d.LayoutFromUser = layouts[0]
635			d.LayoutFromUserMustMatch = true
636		}
637	
638		q := tplimpl.TemplateQuery{
639			Path:     dir,
640			Category: tplimpl.CategoryLayout,
641			Sites:    ps.s.siteVector,
642			Desc:     d,
643		}
644	
645		tinfo := ps.s.TemplateStore.LookupPagesLayout(q)
646		if tinfo == nil {
647			return nil, false, nil
648		}
649	
650		return tinfo, true, nil
651	}
