147	// MakeReadableAndRemoveAllModulePkgDir makes any subdir in dir readable and then
148	// removes the root.
149	// TODO(bep) move this to a more suitable place.
150	func MakeReadableAndRemoveAllModulePkgDir(fs afero.Fs, dir string) (int, error) {
151		// Safe guard
152		// Note that the base directory changed from pkg to gomod_cache in Go 1.23.
153		if !strings.Contains(dir, "pkg") && !strings.Contains(dir, "gomod") {
154			panic(fmt.Sprint("invalid dir:", dir))
155		}
156	
157		counter := 0
158		afero.Walk(fs, dir, func(path string, info os.FileInfo, err error) error {
159			if err != nil {
160				return nil
161			}
162			if info.IsDir() {
163				counter++
164				fs.Chmod(path, 0o777)
165			}
166			return nil
167		})
168	
169		return counter, fs.RemoveAll(dir)
170	}
