172	// IsOsFs returns whether fs is an OsFs or if it fs wraps an OsFs.
173	// TODO(bep) make this more robust.
174	func IsOsFs(fs afero.Fs) bool {
175		var isOsFs bool
176		WalkFilesystems(fs, func(fs afero.Fs) bool {
177			switch fs.(type) {
178			case *afero.MemMapFs:
179				isOsFs = false
180			case *afero.OsFs:
181				isOsFs = true
182			}
183			return isOsFs
