198	// WalkFn is the walk func for WalkFilesystems.
199	type WalkFn func(fs afero.Fs) bool
200	
201	// WalkFilesystems walks fs recursively and calls fn.
202	// If fn returns true, walking is stopped.
203	func WalkFilesystems(fs afero.Fs, fn WalkFn) bool {
204		if fn(fs) {
205			return true
206		}
207	
208		if afs, ok := fs.(FilesystemUnwrapper); ok {
209			if WalkFilesystems(afs.UnwrapFilesystem(), fn) {
210				return true
211			}
212		} else if bfs, ok := fs.(FilesystemsUnwrapper); ok {
213			for _, sf := range bfs.UnwrapFilesystems() {
214				if WalkFilesystems(sf, fn) {
215					return true
216				}
217			}
218		} else if cfs, ok := fs.(overlayfs.FilesystemIterator); ok {
219			for i := range cfs.NumFilesystems() {
220				if WalkFilesystems(cfs.Filesystem(i), fn) {
221					return true
222				}
223			}
224		}
225	
226		return false
227	}
