240	func (m *pageMap) AddFi(fi hugofs.FileMetaInfo, buildConfig *BuildCfg) (pageSourceCount uint64, resourceSourceCount uint64, addErr error) {
241		if fi.IsDir() {
242			return
243		}
244	
245		if m == nil {
246			panic("nil pageMap")
247		}
248	
249		h := m.s.h
250	
251		insertResource := func(fim hugofs.FileMetaInfo) error {
252			resourceSourceCount++
253			pi := fi.Meta().PathInfo
254			key := pi.Base()
255			tree := m.treeResources
256	
257			tree.Lock(true)
258			defer tree.Unlock(true)
259	
260			if pi.IsContent() {
261				pm, err := h.newPageMetaSourceFromFile(fi)
262				if err != nil {
263					return fmt.Errorf("failed to create page from file %q: %w", fi.Meta().Filename, err)
264				}
265				pm.bundled = true
266				m.treeResources.Insert(key, pm)
267			} else {
268				r := func() (hugio.ReadSeekCloser, error) {
269					return fim.Meta().Open()
270				}
271				// Create one dimension now, the rest later on demand.
272				rs := &resourceSource{path: pi, opener: r, fi: fim, sv: fim.Meta().SitesMatrix.VectorSample()}
273				m.treeResources.Insert(key, rs)
274			}
275	
276			return nil
277		}
278	
279		meta := fi.Meta()
280		pi := meta.PathInfo
281	
282		switch pi.Type() {
283		case paths.TypeFile, paths.TypeContentResource:
284			m.s.Log.Trace(logg.StringFunc(
285				func() string {
286					return fmt.Sprintf("insert resource: %q", fi.Meta().Filename)
287				},
288			))
289			if err := insertResource(fi); err != nil {
290				addErr = err
291				return
292			}
293		case paths.TypeContentData:
294			pc, rc, err := m.addPagesFromGoTmplFi(fi, buildConfig)
295			pageSourceCount += pc
296			resourceSourceCount += rc
297			if err != nil {
298				addErr = err
299				return
300			}
301	
302		default:
303			m.s.Log.Trace(logg.StringFunc(
304				func() string {
305					return fmt.Sprintf("insert bundle: %q", fi.Meta().Filename)
306				},
307			))
308	
309			pageSourceCount++
310	
311			pm, err := h.newPageMetaSourceFromFile(fi)
312			if err != nil {
313				addErr = fmt.Errorf("failed to create page meta from file %q: %w", fi.Meta().Filename, err)
314				return
315			}
316	
317			m.treePages.InsertWithLock(pm.pathInfo.Base(), pm)
318		}
319		return
320	}
