322	func (m *pageMap) addPagesFromGoTmplFi(fi hugofs.FileMetaInfo, buildConfig *BuildCfg) (pageCount uint64, resourceCount uint64, addErr error) {
323		meta := fi.Meta()
324		pi := meta.PathInfo
325	
326		m.s.Log.Trace(logg.StringFunc(
327			func() string {
328				return fmt.Sprintf("insert pages from data file: %q", fi.Meta().Filename)
329			},
330		))
331	
332		if !files.IsGoTmplExt(pi.Ext()) {
333			addErr = fmt.Errorf("unsupported data file extension %q", pi.Ext())
334			return
335		}
336	
337		sitesMatrix := fi.Meta().SitesMatrix
338	
339		s := m.s.h.resolveFirstSite(sitesMatrix)
340		h := s.h
341	
342		contentAdapter := s.pageMap.treePagesFromTemplateAdapters.Get(pi.Base())
343		var rebuild bool
344		if contentAdapter != nil {
345			// Rebuild
346			contentAdapter = contentAdapter.CloneForGoTmpl(fi)
347			rebuild = true
348		} else {
349			contentAdapter = pagesfromdata.NewPagesFromTemplate(
350				pagesfromdata.PagesFromTemplateOptions{
351					GoTmplFi: fi,
352					Site:     s,
353					DepsFromSite: func(s page.Site) pagesfromdata.PagesFromTemplateDeps {
354						ss := s.(*Site)
355						return pagesfromdata.PagesFromTemplateDeps{
356							TemplateStore: ss.GetTemplateStore(),
357						}
358					},
359					DependencyManager: s.Conf.NewIdentityManager(),
360					Watching:          s.Conf.Watching(),
361					HandlePage: func(pt *pagesfromdata.PagesFromTemplate, pe *pagemeta.PageConfigEarly) error {
362						s := pt.Site.(*Site)
363	
364						if err := pe.CompileForPagesFromDataPre(pt.GoTmplFi.Meta().PathInfo.Base(), m.s.Log, s.conf.MediaTypes.Config); err != nil {
365							return err
366						}
367	
368						ps, err := s.h.newPageMetaSourceForContentAdapter(fi, s.siteVector, pe)
369						if err != nil {
370							return err
371						}
372	
373						if ps == nil {
374							// Disabled page.
375							return nil
376						}
377	
378						u, n, replaced := s.pageMap.treePages.InsertWithLock(ps.pathInfo.Base(), ps)
379	
380						if h.isRebuild() {
381							if replaced {
382								pt.AddChange(cnh.GetIdentity(n))
383							} else {
384								pt.AddChange(cnh.GetIdentity(u))
385								// New content not in use anywhere.
386								// To make sure that these gets listed in any site.RegularPages ranges or similar
387								// we could invalidate everything, but first try to collect a sample set
388								// from the surrounding pages.
389								var surroundingIDs []identity.Identity
390								ids := h.pageTrees.collectIdentitiesSurrounding(pi.Base(), 10)
391								if len(ids) > 0 {
392									surroundingIDs = append(surroundingIDs, ids...)
393								} else {
394									// No surrounding pages found, so invalidate everything.
395									surroundingIDs = []identity.Identity{identity.GenghisKhan}
396								}
397								for _, id := range surroundingIDs {
398									pt.AddChange(id)
399								}
400							}
401						}
402	
403						return nil
404					},
405					HandleResource: func(pt *pagesfromdata.PagesFromTemplate, rc *pagemeta.ResourceConfig) error {
406						s := pt.Site.(*Site)
407						if err := rc.Compile(
408							pt.GoTmplFi.Meta().PathInfo.Base(),
409							pt.GoTmplFi,
410							s.Conf,
411							s.conf.MediaTypes.Config,
412						); err != nil {
413							return err
414						}
415	
416						// Create one dimension now, the rest later on demand.
417						rs := &resourceSource{path: rc.PathInfo, rc: rc, opener: nil, fi: pt.GoTmplFi, sv: s.siteVector}
418	
419						_, n, updated := s.pageMap.treeResources.InsertWithLock(rs.path.Base(), rs)
420	
421						if h.isRebuild() && updated {
422							pt.AddChange(cnh.GetIdentity(n))
423						}
424						return nil
425					},
426				},
427			)
428	
429			s.pageMap.treePagesFromTemplateAdapters.Insert(pi.Base(), contentAdapter)
430	
431		}
432	
433		handleBuildInfo := func(s *Site, bi pagesfromdata.BuildInfo) {
434			resourceCount += bi.NumResourcesAdded
435			pageCount += bi.NumPagesAdded
436			s.handleContentAdapterChanges(bi, buildConfig)
437		}
438	
439		bi, err := contentAdapter.Execute(context.Background())
440		if err != nil {
441			addErr = err
442			return
443		}
444		handleBuildInfo(s, bi)
445	
446		if !rebuild && (bi.EnableAllLanguages || bi.EnableAllDimensions) {
447			// Clone and insert the adapter for the other sites.
448			var iter iter.Seq[*Site]
449			if bi.EnableAllLanguages {
450				include := func(ss *Site) bool {
451					return s.siteVector.Language() != ss.siteVector.Language()
452				}
453				iter = h.allSiteLanguages(include)
454			} else {
455				include := func(ss *Site) bool {
456					return s.siteVector != ss.siteVector
457				}
458				iter = h.allSites(include)
459			}
460	
461			for ss := range iter {
462				clone := contentAdapter.CloneForSite(ss)
463	
464				// Make sure it gets executed for the first time.
465				bi, err := clone.Execute(context.Background())
466				if err != nil {
467	
468					addErr = err
469					return
470				}
471				handleBuildInfo(ss, bi)
472	
473				// Insert into the correct language tree so it get rebuilt on changes.
474				ss.pageMap.treePagesFromTemplateAdapters.Insert(pi.Base(), clone)
475	
476			}
477		}
478	
479		return
480	}
