482	// The home page is represented with the zero string.
483	// All other keys starts with a leading slash. No trailing slash.
484	// Slashes are Unix-style.
485	func cleanTreeKey(elem ...string) string {
486		var s string
487		if len(elem) > 0 {
488			s = elem[0]
489			if len(elem) > 1 {
490				s = path.Join(elem...)
491			}
492		}
493		s = strings.TrimFunc(s, trimCutsetDotSlashSpace)
494		s = filepath.ToSlash(strings.ToLower(paths.Sanitize(s)))
495		if s == "" || s == "/" {
496			return ""
497		}
498		if s[0] != '/' {
499			s = "/" + s
500		}
501		return s
502	}
503

700		h.data = make(map[string]any)
701		w := hugofs.NewWalkway(
702			hugofs.WalkwayConfig{
703				Fs:         h.PathSpec.BaseFs.Data.Fs,
704				IgnoreFile: h.SourceSpec.IgnoreFile,
705				PathParser: h.Conf.PathParser(),
706				WalkFn: func(ctx context.Context, path string, fi hugofs.FileMetaInfo) error {
707					if fi.IsDir() {
708						return nil
709					}
710					pi := fi.Meta().PathInfo
711					if pi == nil {
712						panic("no path info")
713					}
714					return h.handleDataFile(source.NewFileInfo(fi))
715				},
716			})
717	
718		if err := w.Walk(); err != nil {
719			return err
720		}
721		return nil
722	}
