80	func (r *PostPublishResource) GetFieldString(pattern string) (string, bool) {
81		if r == nil {
82			panic("resource is nil")
83		}
84		prefixIdx := strings.Index(pattern, r.prefix)
85		if prefixIdx == -1 {
86			// Not a method on this resource.
87			return "", false
88		}
89	
90		fieldAccessor := pattern[prefixIdx+len(r.prefix) : strings.Index(pattern, PostProcessSuffix)]
91	
92		d := r.delegate
93		switch {
94		case fieldAccessor == "RelPermalink":
95			return d.RelPermalink(), true
96		case fieldAccessor == "Permalink":
97			return d.Permalink(), true
98		case fieldAccessor == "Name":
99			return d.Name(), true
100		case fieldAccessor == "Title":
101			return d.Title(), true
102		case fieldAccessor == "ResourceType":
103			return d.ResourceType(), true
104		case fieldAccessor == "Content":
105			content, err := d.(resource.ContentProvider).Content(context.Background())
106			if err != nil {
107				return "", true
108			}
109			return cast.ToString(content), true
110		case strings.HasPrefix(fieldAccessor, "MediaType"):
111			return r.fieldToString(d.MediaType(), fieldAccessor), true
112		case fieldAccessor == "Data.Integrity":
113			return cast.ToString((d.Data().(map[string]any)["Integrity"])), true
114		default:
115			panic(fmt.Sprintf("unknown field accessor %q", fieldAccessor))
116		}
117	}
