119	func (r *PostPublishResource) fieldToString(receiver any, path string) string {
120		fieldname := strings.Split(path, ".")[1]
121	
122		receiverv := reflect.ValueOf(receiver)
123		switch receiverv.Kind() {
124		case reflect.Map:
125			v := receiverv.MapIndex(reflect.ValueOf(fieldname))
126			return cast.ToString(v.Interface())
127		default:
128			v := receiverv.FieldByName(fieldname)
129			if !v.IsValid() {
130				method := hreflect.GetMethodByName(receiverv, fieldname)
131				if method.IsValid() {
132					vals := method.Call(nil)
133					if len(vals) > 0 {
134						v = vals[0]
135					}
136	
137				}
138			}
139	
140			if v.IsValid() {
141				return cast.ToString(v.Interface())
142			}
143			return ""
144		}
145	}
