1219	func decodeConfigFromParams(fs afero.Fs, logger loggers.Logger, bcfg config.BaseConfig, p config.Provider, target *Config, keys []string) error {
1220		var decoderSetups []decodeWeight
1221	
1222		if len(keys) == 0 {
1223			for _, v := range allDecoderSetups {
1224				decoderSetups = append(decoderSetups, v)
1225			}
1226		} else {
1227			for _, key := range keys {
1228				if v, found := allDecoderSetups[key]; found {
1229					decoderSetups = append(decoderSetups, v)
1230				} else {
1231					logger.Warnf("Skip unknown config key %q", key)
1232				}
1233			}
1234		}
1235	
1236		// Sort them to get the dependency order right.
1237		sort.Slice(decoderSetups, func(i, j int) bool {
1238			ki, kj := decoderSetups[i], decoderSetups[j]
1239			if ki.weight == kj.weight {
1240				return ki.key < kj.key
1241			}
1242			return ki.weight < kj.weight
1243		})
1244	
1245		for _, v := range decoderSetups {
1246			p := decodeConfig{p: p, c: target, fs: fs, bcfg: bcfg, logger: logger}
1247			if err := v.decode(v, p); err != nil {
1248				return fmt.Errorf("failed to decode %q: %w", v.key, err)
1249			}

