632	// shouldRender returns whether this output format should be rendered or not.
633	func (cfg *BuildCfg) shouldRender(infol logg.LevelLogger, p *pageState) bool {
634		if p.skipRender() {
635			return false
636		}
637	
638		if !p.renderOnce {
639			return true
640		}
641	
642		// The render state is incremented on render and reset when a related change is detected.
643		// Note that this is set per output format.
644		shouldRender := p.renderState == 0
645	
646		if !shouldRender {
647			return false
648		}
649	
650		fastRenderMode := p.s.Conf.FastRenderMode()
651	
652		if !fastRenderMode || !p.s.h.BuildState.IsRebuild() {
653			return shouldRender
654		}
655	
656		if !p.render {
657			// Not be to rendered for this output format.
658			return false
659		}
660	
661		if relURL := p.getRelURL(); relURL != "" {
662			if cfg.RecentlyTouched.Contains(relURL) {
663				infol.Logf("render recently touched URL %q (%s)", relURL, p.outputFormat().Name)
664				return true
665			}
666		}
667	
668		// In fast render mode, we want to avoid re-rendering the sitemaps etc. and
669		// other big listings whenever we e.g. change a content file,
670		// but we want partial renders of the recently touched pages to also include
671		// alternative formats of the same HTML page (e.g. RSS, JSON).
672		for _, po := range p.pageOutputs {
673			if po.render && po.f.IsHTML && cfg.RecentlyTouched.Contains(po.getRelURL()) {
674				infol.Logf("render recently touched URL %q, %s version of %s", po.getRelURL(), po.f.Name, p.outputFormat().Name)
675				return true
676			}
677		}
678	
679		return false
680	}
