45	func LoadConfig(d ConfigSourceDescriptor) (configs *Configs, err error) {
46		defer func() {
47			if r := recover(); r != nil {
48				err = fmt.Errorf("failed to load config: %v", r)
49				debug.PrintStack()
50			}
51		}()
52	
53		if len(d.Environ) == 0 && !hugo.IsRunningAsTest() {
54			d.Environ = os.Environ()
55		}
56	
57		if d.Logger == nil {
58			d.Logger = loggers.NewDefault()
59		}
60	
61		l := &configLoader{ConfigSourceDescriptor: d, cfg: config.New()}
62		// Make sure we always do this, even in error situations,
63		// as we have commands (e.g. "hugo mod init") that will
64		// use a partial configuration to do its job.
65		defer l.deleteMergeStrategies()
66		res, _, err := l.loadConfigMain(d)
67		if err != nil {
68			return nil, fmt.Errorf("failed to load config: %w", err)
69		}
70	
71		configs, err = fromLoadConfigResult(d.Fs, d.Logger, res)
72		if err != nil {
73			return nil, fmt.Errorf("failed to create config from result: %w", err)
74		}
75	
76		moduleConfig, modulesClient, err := l.loadModules(configs, d.IgnoreModuleDoesNotExist)
77		if err != nil {
78			return nil, fmt.Errorf("failed to load modules: %w", err)
79		}
80	
81		if len(l.ModulesConfigFiles) > 0 {
82			// Config merged in from modules.
83			// Re-read the config.
84			configs, err = fromLoadConfigResult(d.Fs, d.Logger, res)
85			if err != nil {
86				return nil, fmt.Errorf("failed to create config from modules config: %w", err)
87			}
88			if err := configs.transientErr(); err != nil {
89				return nil, fmt.Errorf("failed to create config from modules config: %w", err)
90			}
91			configs.LoadingInfo.ConfigFiles = append(configs.LoadingInfo.ConfigFiles, l.ModulesConfigFiles...)
92		} else if err := configs.transientErr(); err != nil {
93			return nil, fmt.Errorf("failed to create config: %w", err)
94		}
95	
96		configs.Modules = moduleConfig.AllModules
97		configs.ModulesClient = modulesClient
98	
99		if !d.SkipNpmCheck && npm.NpmPackNeedsUpdate(d.Fs, configs.Modules) {
100			d.Logger.Warnln(`npm dependencies are out of sync, please run "hugo mod npm pack" (you may also want to run "npm install" after that)`)
101		}
102	
103		if err := configs.Init(d.Fs, d.Logger); err != nil {
104			return nil, fmt.Errorf("failed to init config: %w", err)
105		}
106	
107		loggers.SetGlobalLogger(d.Logger)
108	
109		return
110	}
