122		Filename string
123	
124		// The (optional) directory for additional configuration files.
125		ConfigDir string
126	
127		// production, development
128		Environment string
129	
130		// Defaults to os.Environ if not set.
131		Environ []string
132	
133		// If set, this will be used to ignore the module does not exist error.
134		IgnoreModuleDoesNotExist bool
135	
136		// If set, skip the npm pack staleness check (used by hugo mod npm pack).
137		SkipNpmCheck bool
138	}
