157	// Handle some legacy values.
158	func (l configLoader) applyConfigAliases() error {
159		aliases := []types.KeyValueStr{
160			{Key: "indexes", Value: "taxonomies"},
161			{Key: "logI18nWarnings", Value: "printI18nWarnings"},
162			{Key: "logPathWarnings", Value: "printPathWarnings"},
163			{Key: "ignoreErrors", Value: "ignoreLogs"},
164		}
165	
166		for _, alias := range aliases {
