218	func (l configLoader) applyOsEnvOverrides(environ []string) error {
219		if len(environ) == 0 {
220			return nil
221		}
222	
223		const delim = "__env__delim"
224	
225		// Extract all that start with the HUGO prefix.
226		// The delimiter is the following rune, usually "_".
227		const hugoEnvPrefix = "HUGO"
228		var hugoEnv []types.KeyValueStr
229		for _, v := range environ {
230			key, val := config.SplitEnvVar(v)
231			if after, ok := strings.CutPrefix(key, hugoEnvPrefix); ok {
232				delimiterAndKey := after
233				if len(delimiterAndKey) < 2 {
234					continue
235				}
236				// Allow delimiters to be case sensitive.
237				// It turns out there isn't that many allowed special
238				// chars in environment variables when used in Bash and similar,
239				// so variables on the form HUGOxPARAMSxFOO=bar is one option.
240				key := strings.ReplaceAll(delimiterAndKey[1:], delimiterAndKey[:1], delim)
241				key = strings.ToLower(key)
242				hugoEnv = append(hugoEnv, types.KeyValueStr{
243					Key:   key,
244					Value: val,
245				})
246	
247			}
248		}
249	
250		for _, env := range hugoEnv {
251			existing, nestedKey, owner, err := hmaps.GetNestedParamFn(env.Key, delim, l.cfg.Get)
252			if err != nil {
253				return err
254			}
255	
256			if existing != nil {
257				val, err := metadecoders.Default.UnmarshalStringTo(env.Value, existing)
258				if err == nil {
259					val = l.envValToVal(env.Key, val)
260					if owner != nil {
261						owner[nestedKey] = val
262					} else {
263						l.cfg.Set(env.Key, val)
264					}
265					continue
266				}
267			}
268	
269			if owner != nil && nestedKey != "" {
270				owner[nestedKey] = env.Value
271			} else {
272				var val any
273				key := strings.ReplaceAll(env.Key, delim, ".")
274				_, ok := allDecoderSetups[key]
275				if ok {
276					// A map.
277					if v, err := metadecoders.Default.UnmarshalStringTo(env.Value, map[string]any{}); err == nil {
278						val = v
279					}
280				}
281	
282				if val == nil {
283					// A string.
284					val = l.envStringToVal(key, env.Value)
285				}
286				l.cfg.Set(key, val)
287			}
288	
289		}
290	
291		return nil
292	}
293	
294	func (l *configLoader) envValToVal(k string, v any) any {
295		switch v := v.(type) {
296		case string:
297			return l.envStringToVal(k, v)
298		default:
299			return v
300		}

