462	func (h *HugoSites) filterAndJoinErrors(errs []error) error {
463		if len(errs) == 0 {
464			return nil
465		}
466	
467		seen := map[string]bool{}
468		var n int
469		for _, err := range errs {
470			if err == nil {
471				continue
472			}
473			errMsg := herrors.Cause(err).Error() // We don't need to see many "Could not resolve "@alpinejs/persists""
474			if !seen[errMsg] {
475				seen[errMsg] = true
476				errs[n] = err
477				n++
478			}
479		}
480		errs = errs[:n]
481	
482		for i, err := range errs {
483			errs[i] = herrors.ImproveRenderErr(err)
484		}
485	
486		const limit = 10
487		if len(errs) > limit {
488			errs = errs[:limit]
489		}
490		return errors.Join(errs...)
491	}
