699	func (h *HugoSites) loadData() error {
700		h.data = make(map[string]any)
701		w := hugofs.NewWalkway(
702			hugofs.WalkwayConfig{
703				Fs:         h.PathSpec.BaseFs.Data.Fs,
704				IgnoreFile: h.SourceSpec.IgnoreFile,
705				PathParser: h.Conf.PathParser(),
706				WalkFn: func(ctx context.Context, path string, fi hugofs.FileMetaInfo) error {
707					if fi.IsDir() {
708						return nil
709					}
710					pi := fi.Meta().PathInfo
711					if pi == nil {
712						panic("no path info")
713					}
714					return h.handleDataFile(source.NewFileInfo(fi))
715				},
716			})
717	
718		if err := w.Walk(); err != nil {
719			return err
720		}
721		return nil
722	}
723	
724	func (h *HugoSites) handleDataFile(r *source.File) error {
725		var current map[string]any
726	
727		f, err := r.FileInfo().Meta().Open()
728		if err != nil {
729			return fmt.Errorf("data: failed to open %q: %w", r.LogicalName(), err)
730		}
731		defer f.Close()
732	
733		// Crawl in data tree to insert data
734		current = h.data
735		dataPath := r.FileInfo().Meta().PathInfo.Unnormalized().Dir()[1:]
736		keyParts := strings.SplitSeq(dataPath, "/")
737	
738		for key := range keyParts {
739			if key != "" {
740				if _, ok := current[key]; !ok {
741					current[key] = make(map[string]any)
742				}
743				current = current[key].(map[string]any)
744			}
745		}
746	
747		data, err := h.readData(r)
748		if err != nil {
749			return h.errWithFileContext(err, r)
750		}
751	
752		if data == nil {
753			return nil
754		}
755	
756		// filepath.Walk walks the files in lexical order, '/' comes before '.'
757		higherPrecedentData := current[r.BaseFileName()]
758	
759		switch data.(type) {
760		case map[string]any:
761	
762			switch higherPrecedentData.(type) {
763			case nil:
764				current[r.BaseFileName()] = data
765			case map[string]any:
766				// merge maps: insert entries from data for keys that
767				// don't already exist in higherPrecedentData
768				higherPrecedentMap := higherPrecedentData.(map[string]any)
769				for key, value := range data.(map[string]any) {
770					if _, exists := higherPrecedentMap[key]; exists {
771						// this warning could happen if
772						// 1. A theme uses the same key; the main data folder wins
773						// 2. A sub folder uses the same key: the sub folder wins
774						// TODO(bep) figure out a way to detect 2) above and make that a WARN
775						h.Log.Infof("Data for key '%s' in path '%s' is overridden by higher precedence data already in the data tree", key, r.Path())
776					} else {
777						higherPrecedentMap[key] = value
778					}
779				}
780			default:
781				// can't merge: higherPrecedentData is not a map
782				h.Log.Warnf("The %T data from '%s' overridden by "+
783					"higher precedence %T data already in the data tree", data, r.Path(), higherPrecedentData)
784			}
785	
786		case []any:
787			if higherPrecedentData == nil {
788				current[r.BaseFileName()] = data
789			} else {
790				// we don't merge array data
791				h.Log.Warnf("The %T data from '%s' overridden by "+
792					"higher precedence %T data already in the data tree", data, r.Path(), higherPrecedentData)
793			}
794	
795		default:
796			h.Log.Errorf("unexpected data type %T in file %s", data, r.LogicalName())
797		}
798	
799		return nil

