70	// renderPages renders pages concurrently.
71	func (s *Site) renderPages(ctx *siteRenderContext) error {
72		numWorkers := config.GetNumWorkerMultiplier()
73	
74		results := make(chan error)
75		pages := make(chan *pageState, numWorkers) // buffered for performance
76		errs := make(chan error)
77	
78		go s.errorCollator(results, errs)
79	
80		wg := &sync.WaitGroup{}
81	
82		for range numWorkers {
83			wg.Add(1)
84			go pageRenderer(ctx, s, pages, results, wg)
85		}
86	
87		cfg := ctx.cfg
88	
89		w := &doctree.NodeShiftTreeWalker[contentNode]{
90			Tree: s.pageMap.treePages,
91			Handle: func(key string, n contentNode) (radix.WalkFlag, error) {
92				if p, ok := n.(*pageState); ok {
93					if cfg.shouldRender(ctx.infol, p) {
94						select {
95						case <-s.h.Done():
96							return radix.WalkStop, nil
97						default:
98							pages <- p
99						}
100					}
101				}
102				return radix.WalkContinue, nil
103			},
104		}
105	
106		if err := w.Walk(context.Background()); err != nil {
107			return err
108		}
109	
110		close(pages)
111	
112		wg.Wait()
113	
114		close(results)
115	
116		err := <-errs
117		if err != nil {
118			return fmt.Errorf("%v failed to render pages: %w", s.resolveDimensionNames(), err)
119		}
120		return nil
121	}
