261	// A SourceFilesystem holds the filesystem for a given source type in Hugo (data,
262	// i18n, layouts, static) and additional metadata to be able to use that filesystem
263	// in server mode.
264	type SourceFilesystem struct {
265		// Name matches one in files.ComponentFolders
266		Name string
267	
268		// This is a virtual composite filesystem. It expects path relative to a context.
269		Fs afero.Fs
270	
271		// The source filesystem (usually the OS filesystem).
272		SourceFs afero.Fs
273	
274		// When syncing a source folder to the target (e.g. /public), this may
275		// be set to publish into a subfolder. This is used for static syncing
