294	// StatResource looks for a resource in these filesystems in order: static, assets and finally content.
295	// If found in any of them, it returns FileInfo and the relevant filesystem.
296	// Any non herrors.IsNotExist error will be returned.
297	// An herrors.IsNotExist error will be returned only if all filesystems return such an error.
298	// Note that if we only wanted to find the file, we could create a composite Afero fs,
299	// but we also need to know which filesystem root it lives in.
300	func (s SourceFilesystems) StatResource(lang, filename string) (fi os.FileInfo, fs afero.Fs, err error) {
301		for _, fsToCheck := range []afero.Fs{s.StaticFs(lang), s.Assets.Fs, s.Content.Fs} {
302			fs = fsToCheck
303			fi, err = fs.Stat(filename)
304			if err == nil || !herrors.IsNotExist(err) {
305				return
306			}
307		}
308		// Not found.
309		return
310	}
