328	// ResolvePaths resolves the given filename to a list of paths in the filesystems.
329	func (s *SourceFilesystems) ResolvePaths(filename string) []hugofs.ComponentPath {
330		var cpss []hugofs.ComponentPath
331		for _, rfs := range s.RootFss {
332			cps, err := rfs.ReverseLookup(filename)
333			if err != nil {
334				panic(err)
335			}
336			cpss = append(cpss, cps...)
337		}
338		return cpss
339	}
