341	// MakeStaticPathRelative makes an absolute static filename into a relative one.
342	// It will return an empty string if the filename is not a member of a static filesystem.
343	func (s SourceFilesystems) MakeStaticPathRelative(filename string) string {
344		for _, staticFs := range s.Static {
345			rel, _ := staticFs.MakePathRelative(filename, true)
346			if rel != "" {
347				return rel
348			}
349		}
350		return ""
351	}
