353	// MakePathRelative creates a relative path from the given filename.
354	func (d *SourceFilesystem) MakePathRelative(filename string, checkExists bool) (string, bool) {
355		cps, err := d.ReverseLookup(filename, checkExists)
356		if err != nil {
357			panic(err)
358		}
359		if len(cps) == 0 {
360			return "", false
361		}
362	
363		return filepath.FromSlash(cps[0].Path), true
364	}
365	
366	// ReverseLookup returns the component paths for the given filename.
367	func (d *SourceFilesystem) ReverseLookup(filename string, checkExists bool) ([]hugofs.ComponentPath, error) {
368		var cps []hugofs.ComponentPath
369		hugofs.WalkFilesystems(d.Fs, func(fs afero.Fs) bool {
370			if rfs, ok := fs.(hugofs.ReverseLookupProvder); ok {
371				if c, err := rfs.ReverseLookupComponent(d.Name, filename); err == nil {
372					if checkExists {
373						n := 0
374						for _, cp := range c {
375							if _, err := d.Fs.Stat(filepath.FromSlash(cp.Path)); err == nil {
376								c[n] = cp
377								n++
378							}
379						}
380						c = c[:n]
381					}
382					cps = append(cps, c...)
383				}
384			}
385			return false
386		})
387		return cps, nil
388	}
