417		fi, err := d.Fs.Stat(rel)
418		if err != nil {
419			return rel
420		}
421		if realfi, ok := fi.(hugofs.FileMetaInfo); ok {
422			return realfi.Meta().Filename
423		}
424	
425		return rel
426	}
