48	func Decode(cfg config.Provider) (conf Config, err error) {
49		conf = Default
50	
51		m := cfg.GetStringMap("markup")
52		if m == nil {
53			return
54		}
55		m = hmaps.CleanConfigStringMap(m)
56	
57		normalizeConfig(m)
58	
59		err = mapstructure.WeakDecode(m, &conf)
60		if err != nil {
61			return
62		}
63	
64		if err = conf.Init(); err != nil {
65			return
66		}
67	
68		if err = highlight.ApplyLegacyConfig(cfg, &conf.Highlight); err != nil {
69			return
70		}
71	
72		return
73	}
