75	func normalizeConfig(m map[string]any) {
76		v, err := hmaps.GetNestedParam("goldmark.parser", ".", m)
77		if err == nil {
78			vm := hmaps.ToStringMap(v)
79			// Changed from a bool in 0.81.0
80			if vv, found := vm["attribute"]; found {
81				if vvb, ok := vv.(bool); ok {
82					vm["attribute"] = goldmark_config.ParserAttribute{
83						Title: vvb,
84					}
85				}
86			}
87		}
88	
89		// Handle changes to the Goldmark configuration.
90		v, err = hmaps.GetNestedParam("goldmark.extensions", ".", m)
91		if err == nil {
92			vm := hmaps.ToStringMap(v)
93	
94			// We changed the typographer extension config from a bool to a struct in 0.112.0.
95			migrateGoldmarkConfig(vm, "typographer", goldmark_config.Typographer{Disable: true})
96	
97			// We changed the footnote extension config from a bool to a struct in 0.151.0.
98			migrateGoldmarkConfig(vm, "footnote", goldmark_config.Footnote{Enable: false})
99		}
100	}
101	
102	func migrateGoldmarkConfig(vm map[string]any, key string, falseVal any) {
103		if vv, found := vm[key]; found {
104			if vvb, ok := vv.(bool); ok {
105				if !vvb {
106					vm[key] = falseVal
107				} else {
108					delete(vm, key)
109				}
110			}
111		}
112	}
